#!/usr/bin/env node
/**
 * Build Order sync/check helper [CX-BO-001]
 *
 * Updates the AUTOGENERATED block inside `.GOV/roles_shared/BUILD_ORDER.md`
 * from the current governance state:
 * - `.GOV/roles_shared/SPEC_CURRENT.md`
 * - `.GOV/roles_shared/WP_TRACEABILITY_REGISTRY.md`
 * - `.GOV/roles_shared/TASK_BOARD.md`
 * - Active packet files (official packets + stubs)
 *
 * Usage:
 *   node .GOV/scripts/build-order-sync.mjs
 *   node .GOV/scripts/build-order-sync.mjs --check
 */

import crypto from "node:crypto";
import fs from "node:fs";
import path from "node:path";
import { execFileSync } from "node:child_process";
import { fileURLToPath } from "node:url";

const BUILD_ORDER_PATH = ".GOV/roles_shared/BUILD_ORDER.md";
const SPEC_CURRENT_PATH = ".GOV/roles_shared/SPEC_CURRENT.md";
const TRACE_REGISTRY_PATH = ".GOV/roles_shared/WP_TRACEABILITY_REGISTRY.md";
const TASK_BOARD_PATH = ".GOV/roles_shared/TASK_BOARD.md";

const AUTOGEN_BEGIN = "<!-- BUILD_ORDER_AUTOGEN:BEGIN -->";
const AUTOGEN_END = "<!-- BUILD_ORDER_AUTOGEN:END -->";

function resolveRepoRoot() {
  try {
    const out = execFileSync("git", ["rev-parse", "--show-toplevel"], {
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim();
    if (out) return out;
  } catch {
    // Ignore; fall back to relative-to-file resolution.
  }

  // This file lives at: /.GOV/scripts/build-order-sync.mjs
  // Up 2 => /.GOV => repo root
  return path.resolve(path.dirname(fileURLToPath(import.meta.url)), "../..");
}

function fail(message, details = []) {
  console.error(`[BUILD_ORDER_SYNC] ${message}`);
  for (const line of details) console.error(`  - ${line}`);
  process.exit(1);
}

function readText(filePath) {
  if (!fs.existsSync(filePath)) {
    fail("Missing required file", [filePath]);
  }
  return fs.readFileSync(filePath, "utf8");
}

function normalizePath(p) {
  return String(p || "").replace(/\\/g, "/");
}

function packetIdFromPath(packetPath) {
  const p = normalizePath(packetPath);
  const last = p.split("/").filter(Boolean).pop() || "";
  return last.endsWith(".md") ? last.slice(0, -3) : last;
}

function parseSpecTarget(specCurrentContent) {
  const m = specCurrentContent.match(/Handshake_Master_Spec_v[0-9.]+\.md/);
  return m ? m[0] : "Handshake_Master_Spec_vXX.XXX.md";
}

function parseRegistryRows(content) {
  const rows = [];
  const lines = content.split(/\r?\n/);
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index];
    if (!line.trim().startsWith("|")) continue;
    const parts = line.split("|").slice(1, -1).map((p) => p.trim());
    if (parts.length < 2) continue;

    const baseWpId = parts[0];
    const activePacket = parts[1];
    const taskBoardCell = parts[2] || "";
    const notes = parts[3] || "";
    if (!baseWpId.startsWith("WP-")) continue;

    rows.push({
      baseWpId,
      activePacketPath: normalizePath(activePacket),
      activePacketId: packetIdFromPath(activePacket),
      taskBoardCell,
      notes,
      lineNumber: index + 1,
    });
  }
  return rows;
}

function parseTaskBoardTokens(taskBoardContent) {
  const tokensByWpId = new Map();
  const lines = taskBoardContent.split(/\r?\n/);
  for (const raw of lines) {
    const line = raw.trim();
    const m = line.match(/^- \*\*\[(WP-[^\]]+)\]\*\* - \[([^\]]+)\]\s*$/);
    if (!m) continue;
    tokensByWpId.set(m[1], m[2]);
  }
  return tokensByWpId;
}

function parseBuildOrderMeta(packetText) {
  const meta = {
    domain: "UNKNOWN",
    techBlocker: "UNKNOWN",
    valueTier: "UNKNOWN",
    dependsOn: [],
    blocks: [],
    riskTier: "UNKNOWN",
  };

  const lines = packetText.split(/\r?\n/);
  for (const raw of lines) {
    const line = raw.trim();

    const mRisk = line.match(/^-+\s*RISK_TIER\s*:\s*(.+)\s*$/i);
    if (mRisk) meta.riskTier = mRisk[1].trim();

    const mDomain = line.match(/^-+\s*BUILD_ORDER_DOMAIN\s*:\s*(.+)\s*$/i);
    if (mDomain) meta.domain = mDomain[1].trim();

    const mTech = line.match(/^-+\s*BUILD_ORDER_TECH_BLOCKER\s*:\s*(.+)\s*$/i);
    if (mTech) meta.techBlocker = mTech[1].trim();

    const mValue = line.match(/^-+\s*BUILD_ORDER_VALUE_TIER\s*:\s*(.+)\s*$/i);
    if (mValue) meta.valueTier = mValue[1].trim();

    const mDepends = line.match(/^-+\s*BUILD_ORDER_DEPENDS_ON\s*:\s*(.+)\s*$/i);
    if (mDepends) meta.dependsOn = parseWpIdList(mDepends[1]);

    const mBlocks = line.match(/^-+\s*BUILD_ORDER_BLOCKS\s*:\s*(.+)\s*$/i);
    if (mBlocks) meta.blocks = parseWpIdList(mBlocks[1]);
  }

  return meta;
}

function parseWpIdList(raw) {
  const value = String(raw || "").trim();
  if (!value) return [];
  if (/^(none|n\/a|na|<pending>|<fill>)$/i.test(value)) return [];
  return value
    .split(",")
    .map((part) => part.trim())
    .filter(Boolean)
    .map((token) => token.replace(/^-+\s*/, ""))
    .map((id) => id.replace(/-v\d+$/, ""))
    .filter((id) => id.startsWith("WP-"));
}

function formatCell(value) {
  return String(value || "")
    .replace(/\|/g, "\\|")
    .replace(/\r?\n/g, " ")
    .trim();
}

function shortStateFromRegistryCell(taskBoardCell) {
  const cell = String(taskBoardCell || "").trim();
  if (!cell) return "UNKNOWN";
  if (/^Done:/i.test(cell)) return "DONE";
  if (/^In Progress:/i.test(cell)) return "IN_PROGRESS";
  if (/^Ready for Dev:/i.test(cell)) return "READY_FOR_DEV";
  if (/^Blocked:/i.test(cell)) return "BLOCKED";
  if (/^Superseded:/i.test(cell)) return "SUPERSEDED";
  if (/^Stub Backlog/i.test(cell)) return "STUB";
  return "UNKNOWN";
}

function generateAutogenBlock({ specTarget, registryRows, taskBoardTokens, metaByBase, inputsSha256 }) {
  const lines = [];
  lines.push("AUTOGENERATED. Do not edit this block by hand.");
  lines.push("");
  lines.push(`- SPEC_TARGET: ${specTarget}`);
  lines.push(`- INPUT_SHA256: ${inputsSha256}`);
  lines.push(`- UPDATE_COMMAND: just build-order-sync`);
  lines.push("");

  lines.push(
    "| Base WP ID | Active Packet ID | Active Packet Path | BOARD_TOKEN | REGISTRY_STATE | DOMAIN | TECH_BLOCKER | VALUE_TIER | RISK_TIER | DEPENDS_ON | BLOCKS |"
  );
  lines.push(
    "|---|---|---|---|---|---|---|---|---|---|---|"
  );

  const sorted = [...registryRows].sort((a, b) => a.baseWpId.localeCompare(b.baseWpId));
  for (const row of sorted) {
    const meta = metaByBase.get(row.baseWpId) || {
      domain: "UNKNOWN",
      techBlocker: "UNKNOWN",
      valueTier: "UNKNOWN",
      dependsOn: [],
      blocks: [],
      riskTier: "UNKNOWN",
    };

    const boardToken = taskBoardTokens.get(row.activePacketId) || "-";
    const registryState = shortStateFromRegistryCell(row.taskBoardCell);

    lines.push(
      [
        row.baseWpId,
        row.activePacketId,
        row.activePacketPath,
        boardToken,
        registryState,
        meta.domain,
        meta.techBlocker,
        meta.valueTier,
        meta.riskTier,
        meta.dependsOn.length > 0 ? meta.dependsOn.join(", ") : "-",
        meta.blocks.length > 0 ? meta.blocks.join(", ") : "-",
      ].map(formatCell).join(" | ").replace(/^/, "| ").replace(/$/, " |")
    );
  }

  const metaMissing = sorted
    .filter((row) => {
      const meta = metaByBase.get(row.baseWpId);
      if (!meta) return true;
      const unknown = (v) => !v || v === "UNKNOWN" || /^<pending>$/i.test(v) || /^<fill>$/i.test(v);
      return (
        unknown(meta.domain) ||
        unknown(meta.techBlocker) ||
        unknown(meta.valueTier) ||
        unknown(meta.riskTier)
      );
    })
    .map((row) => row.baseWpId);

  lines.push("");
  lines.push("METADATA_GAPS (fill these in the active packet/stub when activating/refreshing build order meta):");
  if (metaMissing.length === 0) {
    lines.push("- none");
  } else {
    lines.push(`- count: ${metaMissing.length}`);
    for (const id of metaMissing.slice(0, 40)) {
      lines.push(`- ${id}`);
    }
    if (metaMissing.length > 40) lines.push("- ...");
  }

  return lines.join("\n");
}

function applyAutogenBlockToFile(originalContent, autogenBlock) {
  const beginIdx = originalContent.indexOf(AUTOGEN_BEGIN);
  const endIdx = originalContent.indexOf(AUTOGEN_END);
  if (beginIdx === -1 || endIdx === -1 || endIdx <= beginIdx) {
    fail("BUILD_ORDER.md is missing AUTOGENERATED markers", [
      `Expected markers in ${BUILD_ORDER_PATH}:`,
      AUTOGEN_BEGIN,
      AUTOGEN_END,
    ]);
  }

  const before = originalContent.slice(0, beginIdx + AUTOGEN_BEGIN.length);
  const after = originalContent.slice(endIdx);
  return `${before}\n${autogenBlock}\n${after}`;
}

function sha256(text) {
  return crypto.createHash("sha256").update(text, "utf8").digest("hex");
}

const args = process.argv.slice(2);
const checkOnly = args.includes("--check");
const repoRoot = path.resolve(resolveRepoRoot());
process.chdir(repoRoot);

const specCurrent = readText(SPEC_CURRENT_PATH);
const specTarget = parseSpecTarget(specCurrent);

const registryContent = readText(TRACE_REGISTRY_PATH);
const registryRows = parseRegistryRows(registryContent);
if (registryRows.length === 0) {
  fail("No registry rows found; cannot build build-order snapshot", [TRACE_REGISTRY_PATH]);
}

const taskBoardContent = readText(TASK_BOARD_PATH);
const taskBoardTokens = parseTaskBoardTokens(taskBoardContent);

const metaByBase = new Map();
const inputsForHash = [];
inputsForHash.push(`SPEC_CURRENT:\n${specCurrent}`);
inputsForHash.push(`WP_TRACEABILITY_REGISTRY:\n${registryContent}`);
inputsForHash.push(`TASK_BOARD:\n${taskBoardContent}`);

for (const row of [...registryRows].sort((a, b) => a.baseWpId.localeCompare(b.baseWpId))) {
  const packetPath = row.activePacketPath;
  if (!packetPath) continue;
  if (!fs.existsSync(packetPath)) {
    // Missing packets are a governance smell, but keep this tool non-blocking.
    continue;
  }
  const text = fs.readFileSync(packetPath, "utf8");
  inputsForHash.push(`${packetPath}:\n${text}`);
  metaByBase.set(row.baseWpId, parseBuildOrderMeta(text));
}

const inputsSha256 = sha256(inputsForHash.join("\n\n---\n\n"));
const autogen = generateAutogenBlock({ specTarget, registryRows, taskBoardTokens, metaByBase, inputsSha256 });

const buildOrderOriginal = readText(BUILD_ORDER_PATH);
const expected = applyAutogenBlockToFile(buildOrderOriginal, autogen);

if (checkOnly) {
  if (expected !== buildOrderOriginal) {
    console.error(`[BUILD_ORDER_CHECK] ${BUILD_ORDER_PATH} is out of date.`);
    console.error("Run: just build-order-sync");
    process.exit(1);
  }
  process.exit(0);
}

if (expected !== buildOrderOriginal) {
  fs.writeFileSync(BUILD_ORDER_PATH, expected, "utf8");
  console.log(`build-order-sync ok: updated ${BUILD_ORDER_PATH}`);
} else {
  console.log(`build-order-sync ok: ${BUILD_ORDER_PATH} already up to date`);
}

